// ── Pull the agent output ─────────────────────────────────────────────────
const responseText = $input.first().json.output ?? '';

const VALID_CATEGORIES = ['Safety','Driver Behavior','Payment','App Issue','Trip Quality','Other'];
const VALID_SEVERITIES  = ['Critical','High','Medium','Low'];

let parsed;
try {
  // Strip markdown fences if model adds them despite instructions
  let clean = responseText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Extract the first JSON object found
  const jsonMatch = clean.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found in response');
  clean = jsonMatch[0];

  parsed = JSON.parse(clean);

  // ── Validate & sanitize each field ──────────────────────────────────────
  // category
  if (!VALID_CATEGORIES.includes(parsed.category)) {
    parsed.category = 'Other';
  }
  // severity
  if (!VALID_SEVERITIES.includes(parsed.severity)) {
    parsed.severity = 'Low';
  }
  // escalate — force to real boolean regardless of what model returned
  if (typeof parsed.escalate === 'string') {
    parsed.escalate = parsed.escalate.toLowerCase() === 'true';
  } else if (typeof parsed.escalate !== 'boolean') {
    parsed.escalate = false;
  }
  // reason — sanitize single quotes for SQL safety, cap length
  if (typeof parsed.reason === 'string') {
    parsed.reason = parsed.reason.replace(/'/g, "''").substring(0, 500);
  } else {
    parsed.reason = 'No reason provided';
  }

  parsed.classificationFailed = false;

} catch(e) {
  parsed = {
    category:             'Other',
    severity:             'Low',
    reason:               'Auto-classification failed — manual review needed',
    escalate:             false,
    classificationFailed: true,
    errorMessage:         e.message
  };
}

// ── Attach complaint identifiers from the loop ───────────────────────────
const loopItem = $('Loop Over Items1').first().json;
parsed.complaintKey = loopItem.ComplaintKey;
parsed.complaintID  = loopItem.ComplaintID;
parsed.description  = loopItem.Description;

return [{ json: parsed }];

